// Split positions + generate SKU for product pool
const positions = $('📋 Parse JSON').first().json.positionen || [];
const invoiceId = $('📄 Create Invoice').first().json.id;
const supplierId = $('🏢 Match Supplier').first().json.supplier_id;
const invoiceDate = $('📋 Parse JSON').first().json.rechnung_datum;

// Hash für Artikel ohne SKU
const simpleHash = (str) => {
  let hash = 0;
  for (let i = 0; i < str.length; i++) {
    const char = str.charCodeAt(i);
    hash = ((hash << 5) - hash) + char;
    hash = hash & hash;
  }
  return 'GEN-' + Math.abs(hash).toString(16).toUpperCase().substring(0, 8);
};

return positions.map((pos, idx) => {
  const description = (pos.beschreibung || 'Unbekannt').replace(/'/g, "''");
  const articleNumber = pos.artikel_nummer || '';
  const sku = articleNumber || simpleHash(description + supplierId);

  return {
    json: {
      invoice_id: invoiceId,
      supplier_id: supplierId,
      position_number: idx + 1,
      article_number: articleNumber,
      description: description,
      quantity: pos.menge || 1,
      unit: pos.einheit || 'Stk',
      unit_price_net: Math.round((Number(pos.einzelpreis_brutto) || 0) / 1.19 * 100) / 100,
      product_sku: sku,
      product_category: pos.kategorie || null,
      invoice_date: invoiceDate
    }
  };
});

// V2: Build MX_02 Request using invoice_date from parsed receipt
const invoiceDate = $('📋 Parse JSON').first().json.rechnung_datum;
const supplierCode = $('🏢 Match Supplier').first().json.supplier_code;
const originalFilename = $('📋 Parse JSON').first().json.original_filename;

// Parse date (Format: "2026-01-02" or "02.01.2026")
let date;
if (invoiceDate && invoiceDate.includes('-')) {
  date = new Date(invoiceDate);
} else if (invoiceDate && invoiceDate.includes('.')) {
  const [day, month, year] = invoiceDate.split('.');
  date = new Date(`${year}-${month}-${day}`);
} else {
  // Fallback: today
  date = new Date();
}

const year = date.getFullYear().toString();
const monthNames = [
  '01-Januar', '02-Februar', '03-März', '04-April',
  '05-Mai', '06-Juni', '07-Juli', '08-August',
  '09-September', '10-Oktober', '11-November', '12-Dezember'
];
const month = monthNames[date.getMonth()];

// Build filename for Drive: YYYY-MM-DD_SUPPLIER_originalname
const driveFilename = `${invoiceDate}_${supplierCode}_${originalFilename}`;

return {
  json: {
    folder_type: 'buchhaltung_month',
    year: year,
    month: month,
    full_path: `Buchhaltung/VERARBEITET/${year}/${month}`,
    drive_filename: driveFilename
  }
};

// FIX 4: Prepare data for Lexware email forwarding
const parsed = $('📋 Parse JSON').first().json;
const invoiceNumber = parsed.rechnung_nummer || 'UNKNOWN';
const supplierName = parsed.lieferant_name || 'Unbekannt';
const storagePath = parsed.storage_path || '';

return {
  json: {
    to: 'bauloewen@inbox.lexware.email',
    subject: `${invoiceNumber} - ${supplierName}`,
    body: 'Automatisch weitergeleitet von BauGenius\n\nRechnungsnummer: ' + invoiceNumber + '\nLieferant: ' + supplierName + '\nBetrag: ' + (parsed.summe_brutto || 0).toFixed(2) + ' EUR',
    storage_path: storagePath,
    has_pdf: !!storagePath,
    invoice_id: parsed.invoice_id,
    download_url: storagePath ? `https://yetwntwayhmzmhhgdkli.supabase.co/storage/v1/object/public/${storagePath}` : ''
  }
};

