try {
  const downloadNode = $('📎 Download Binary').first();
  binary = downloadNode.binary || {};
} catch (e) {
  // Inline path - no binary available, that's fine
}

// Pass everything through
const result = { json: { ...parsed } };
if (Object.keys(binary).length > 0) {
  result.binary = binary;
}
return [result];

// Get original parsed data
const parsed = $('📋 Parse JSON').first().json;

// Get Gemini response
const geminiResponse = $input.first().json;

let result = { ...parsed };

// Parse Gemini response
let validatorData;
try {
  const text = geminiResponse.content?.parts?.[0]?.text || 
               geminiResponse.text || 
               JSON.stringify(geminiResponse);
  const cleanJson = text.replace(/```json\s*/gi, '').replace(/```/g, '').trim();
  validatorData = JSON.parse(cleanJson);
} catch (e) {
  return [{ 
    json: { 
      ...result, 
      _validation_skipped: true,
      _validation_error: e.message 
    }
  }];
}

// Apply corrections
if (validatorData.corrections) {
  for (const [key, value] of Object.entries(validatorData.corrections)) {
    result[key] = value;
  }
}

// Recalculate due_date if datum corrected
if (validatorData.corrections?.rechnung_datum) {
  const d = new Date(validatorData.corrections.rechnung_datum);
  d.setDate(d.getDate() + (result.payment_terms_days || 14));
  result.due_date = d.toISOString().split('T')[0];
}

// Recalculate net/gross if corrected
if (validatorData.corrections?.summe_brutto || validatorData.corrections?.summe_netto) {
  const vat = result.mwst_prozent || 19;
  if (validatorData.corrections.summe_brutto && !validatorData.corrections.summe_netto) {
    result.summe_netto = Math.round((result.summe_brutto / (1 + vat / 100)) * 100) / 100;
  } else if (validatorData.corrections.summe_netto && !validatorData.corrections.summe_brutto) {
    result.summe_brutto = Math.round(result.summe_netto * (1 + vat / 100) * 100) / 100;
  }
}

// Add validation metadata
result._validated = validatorData.valid;
result._confidence = validatorData.confidence;
result._issues = validatorData.issues || [];

return [{ json: result }];

// Extract event data from MX_00_Event_Router payload
// V4: Removed primary_file_id — multi-attachment loop handles individual files
const body = $input.first().json.body || $input.first().json;

// Parse file_ids - could be string or array
let fileIds = body.file_ids || body.payload?.file_ids || [];
if (typeof fileIds === 'string') {
  try {
    fileIds = JSON.parse(fileIds);
  } catch (e) {
    fileIds = [];
  }
}

return {
  json: {
    // IDs (no invoice_id here — generated per attachment in Split File IDs)
    event_id: body.event_id || body.id,

    // Superchat IDs
    superchat_message_id: body.superchat_message_id || body.payload?.superchat_message_id,
    superchat_conversation_id: body.superchat_conversation_id || body.payload?.superchat_conversation_id,

    // File handling — keep full array, no primary_file_id
    file_ids: fileIds,

    // Email metadata
    email_from: body.from_address || body.payload?.from_address || '',
    email_subject: (body.subject || body.payload?.subject || '').replace(/'/g, "''"),
    email_received_at: body.received_at || new Date().toISOString(),

    // Doc type (INVOICE_IN or CREDIT_NOTE)
    doc_type: body.doc_type || body.payload?.doc_type || 'INVOICE_IN',
    confidence: body.confidence || body.payload?.confidence || 0.9,

    // Email body (from MX_03 V2)
    body_preview: body.body_preview || body.payload?.body_preview || '',

    // Idempotency base key (will be extended per file in Split File IDs)
    idempotency_key: `m6_${body.superchat_message_id || body.payload?.superchat_message_id}`
  }
};

// FIX 2: Detect credit notes based on sender and subject
const data = $input.first().json;
const emailFrom = (data.email_from || '').toLowerCase();
const emailSubject = (data.email_subject || '').toLowerCase();

let invoiceType = 'invoice';
let docType = data.doc_type || 'INVOICE_IN';

// Rule 1: besser zuhause sendet NUR Gutschriften
if (emailFrom.includes('besser zuhause') || emailFrom.includes('besserzuhause')) {
  invoiceType = 'credit_note';
  docType = 'CREDIT_NOTE';
}

// Rule 2: Betreff enthält Gutschrift/Storno
